#include <bits/stdc++.h>
using namespace std;

int a[2005], la, b[2005], lb, ans[4005], lans;

void to_int(string s, int a[], int &l) {
	l = s.size();
	while (s[0] == '0' && l > 1) {
		s.erase(s.begin());
		l--;
	}
	for (int i = l - 1; i >= 0; i--) {
		a[i] = s[l - i - 1] - '0';
	}
}

void print(int a[], int la) {
	for (int i = 0; i < la; i++) {
		cout << a[la - i - 1];
	}
	cout << endl;
}

void solve(int a[], int la, int b[], int lb, int ans[], int &lans) {
	lans = la + lb - 1;
	memset(ans, 0, sizeof(ans));
	for (int i = 0; i < lb; i++) {
		for (int j = 0; j < la; j++) {
			int t = ans[i + j] + b[i] * a[j];
			ans[i + j] = t % 10;
			ans[i + j + 1] += t / 10;
			if ((i == lb - 1) && (j == la - 1)) {
				if (t / 10) {
					lans++;
				}
			}
		}
	}
}

int main() {
	string s1, s2;
	cin >> s1 >> s2;
	to_int(s1, a, la);
	to_int(s2, b, lb);
	solve(a, la, b, lb, ans, lans);
	print(ans, lans);
	return 0;
}
